SELECT p.id, p.org_id AS orgId, p.operation_id AS operationId, p.start_time AS startTime, p.end_time AS endTime, p.operation_level AS operationLevel, p.affected_households AS affectedHouseholds, p.reason, p.remark, p.status, p.create_time AS createTime, p.create_id AS createId, p.update_time AS updateTime, p.update_id AS updateId, a.detail_address AS detailAddress, o.organization_name AS organizationName FROM gs_cutoff_plan p INNER JOIN gs_cutoff_area_node a ON p.id = a.source_id AND a.source_type = 'PLAN' LEFT JOIN tbl_organization o ON p.org_id = o.id
p.deleted = 0
AND p.start_time >= #{request.startTime}
AND p.end_time <= #{request.endTime}
AND p.operation_level = #{request.operationLevel}
